GET Levcon API: heutige AI-News-Ausgabe (Summary + Items).
Auth via X-Levcon-Api-Key Header.
Response: { date, summaryDe, summaryEn, items[] }

parameters.jsCode:
// Format LinkedIn post text per template in templates/linkedin-post-template.md
// Input: item.json = { date, summaryDe, summaryEn, items[] }
// Output: { postText: string, dateDe: string, dateEn: string }

const input = items[0].json;
const today = input.date || new Date().toISOString().substring(0, 10);

// German date format: "DD. MMMM YYYY" (z.B. "25. Juni 2025")
const DE_MONTHS = ['Januar', 'Februar', 'März', 'April', 'Mai', 'Juni', 'Juli', 'August', 'September', 'Oktober', 'November', 'Dezember'];
const d = new Date(today + 'T00:00:00Z');
const dateDe = `${d.getUTCDate()}. ${DE_MONTHS[d.getUTCMonth()]} ${d.getUTCFullYear()}`;

// English date format: "MMMM D, YYYY"
const EN_MONTHS = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
const dateEn = `${EN_MONTHS[d.getUTCMonth()]} ${d.getUTCDate()}, ${d.getUTCFullYear()}`;

const summaryDe = (input.summaryDe || '').trim();
const rawItems = Array.isArray(input.items) ? input.items : [];

// Take max 5 headlines (LinkedIn best practice)
const MAX_HEADLINES = 5;
const top = rawItems.slice(0, MAX_HEADLINES);

function cleanUrl(u) {
  try {
    const parsed = new URL(u);
    ['utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content', 'fbclid', 'gclid'].forEach(p => parsed.searchParams.delete(p));
    let clean = parsed.origin + parsed.pathname;
    if (parsed.search) clean += parsed.search;
    return clean;
  } catch (e) {
    return u || '';
  }
}

function truncate(s, maxLen) {
  if (!s) return '';
  s = s.trim();
  if (s.length <= maxLen) return s;
  return s.substring(0, maxLen - 1).trimEnd() + '…';
}

const lines = [];
lines.push(`KI-News des Tages · ${dateDe}`);
lines.push('');
lines.push(summaryDe || 'Heute ein ruhiger Tag in der KI-Welt.');
lines.push('');

if (top.length === 0) {
  lines.push('Heute keine nennenswerten Meldungen.');
} else {
  top.forEach((item, idx) => {
    const headline = truncate(item.headline || item.title || '', 200);
    const source = (item.source || '').trim();
    const url = cleanUrl(item.sourceUrl || item.url || item.link || '');
    lines.push(`▸ ${headline}${source ? ' — ' + source : ''}`);
    if (url) lines.push(`  ${url}`);
    lines.push('');
  });
}

const siteUrl = ($env && $env.NEXT_PUBLIC_SITE_URL) || 'https://levcon.ai';
lines.push(`Vollständige Ausgabe mit Kurzzusammenfassungen: ${siteUrl}/#news`);
lines.push('');
lines.push('#KI #AI #KünstlicheIntelligenz #Levcon');

let postText = lines.join('\n');

// LinkedIn hard limit: 3000 chars for standard posts
if (postText.length > 3000) {
  postText = postText.substring(0, 2997) + '...';
}

return [{
  json: {
    postText,
    dateDe,
    dateEn,
    headlineCount: top.length,
    charCount: postText.length
  }
}];

